function New-Diagram {
  param(
    [string]$Path,
    [string]$Title,
    [array]$Boxes
  )

  Add-Type -AssemblyName System.Drawing
  $bmp = New-Object System.Drawing.Bitmap 1400, 760
  $gfx = [System.Drawing.Graphics]::FromImage($bmp)
  $gfx.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::AntiAlias
  $gfx.Clear([System.Drawing.Color]::FromArgb(247, 250, 252))

  $fontTitle = New-Object System.Drawing.Font "Segoe UI", 28, ([System.Drawing.FontStyle]::Bold)
  $fontBox = New-Object System.Drawing.Font "Segoe UI", 18, ([System.Drawing.FontStyle]::Bold)
  $fontSmall = New-Object System.Drawing.Font "Segoe UI", 13, ([System.Drawing.FontStyle]::Regular)
  $brushText = New-Object System.Drawing.SolidBrush ([System.Drawing.Color]::FromArgb(22, 36, 48))
  $brushBlue = New-Object System.Drawing.SolidBrush ([System.Drawing.Color]::FromArgb(208, 244, 239))
  $brushAmber = New-Object System.Drawing.SolidBrush ([System.Drawing.Color]::FromArgb(255, 238, 189))
  $pen = New-Object System.Drawing.Pen ([System.Drawing.Color]::FromArgb(84, 105, 122)), 3
  $arrowPen = New-Object System.Drawing.Pen ([System.Drawing.Color]::FromArgb(60, 130, 122)), 4
  $arrowPen.CustomEndCap = New-Object System.Drawing.Drawing2D.AdjustableArrowCap 6, 8

  $gfx.DrawString($Title, $fontTitle, $brushText, 44, 34)

  for ($i = 0; $i -lt $Boxes.Count; $i++) {
    $box = $Boxes[$i]
    $rect = New-Object System.Drawing.Rectangle $box.X, $box.Y, $box.W, $box.H
    $brush = if ($i % 2 -eq 0) { $brushBlue } else { $brushAmber }
    $gfx.FillRectangle($brush, $rect)
    $gfx.DrawRectangle($pen, $rect)
    $gfx.DrawString($box.Title, $fontBox, $brushText, ($box.X + 22), ($box.Y + 18))
    $gfx.DrawString($box.Text, $fontSmall, $brushText, (New-Object System.Drawing.RectangleF ($box.X + 22), ($box.Y + 62), ($box.W - 44), ($box.H - 74)))
    if ($i -lt $Boxes.Count - 1) {
      $next = $Boxes[$i + 1]
      $gfx.DrawLine($arrowPen, ($box.X + $box.W), ($box.Y + [int]($box.H / 2)), $next.X, ($next.Y + [int]($next.H / 2)))
    }
  }

  $bmp.Save($Path, [System.Drawing.Imaging.ImageFormat]::Png)
  $gfx.Dispose()
  $bmp.Dispose()
}

