if (!(Test-Path -LiteralPath $TemplatePath)) {
  throw "Template not found: $TemplatePath"
}

Copy-Item -LiteralPath $TemplatePath -Destination $OutputPath -Force

$word = New-Object -ComObject Word.Application
$word.Visible = $false
$word.DisplayAlerts = 0

try {
  $doc = $word.Documents.Open($OutputPath)

  $tocStart = $null
  for ($i = 1; $i -le $doc.Paragraphs.Count; $i++) {
    $text = $doc.Paragraphs.Item($i).Range.Text.Trim()
    if ($text -eq "СОДЕРЖАНИЕ") {
      $tocStart = $doc.Paragraphs.Item($i).Range.Start
      break
    }
  }
  if ($null -eq $tocStart) {
    throw "Cannot find СОДЕРЖАНИЕ in template"
  }

  $deleteRange = $doc.Range($tocStart, $doc.Content.End - 1)
  $deleteRange.Delete()
  $range = $doc.Range($tocStart, $tocStart)
  $range.Select()
  $sel = $word.Selection

  function Set-NormalFormat {
    $sel.Style = $doc.Styles.Item($wdStyleNormal)
    $sel.ParagraphFormat.Alignment = $wdAlignParagraphJustify
    $sel.ParagraphFormat.FirstLineIndent = $word.CentimetersToPoints(1.25)
    $sel.ParagraphFormat.SpaceAfter = 0
    $sel.ParagraphFormat.LineSpacingRule = 1
  }

  function Add-Para {
    param([string]$Text)
    Set-NormalFormat
    $sel.TypeText($Text)
    $sel.TypeParagraph()
  }

  function Add-Heading1 {
    param([string]$Text)
    $sel.Style = $doc.Styles.Item($wdStyleHeading1)
    $sel.ParagraphFormat.Alignment = $wdAlignParagraphCenter
    $sel.ParagraphFormat.FirstLineIndent = 0
    $start = $sel.Range.Start
    $sel.TypeText($Text)
    $headingRange = $doc.Range($start, $sel.Range.End)
    try { $headingRange.ListFormat.RemoveNumbers() | Out-Null } catch {}
    $sel.TypeParagraph()
  }

  function Add-Heading2 {
    param([string]$Text)
    $sel.Style = $doc.Styles.Item($wdStyleHeading2)
    $sel.ParagraphFormat.Alignment = $wdAlignParagraphJustify
    $sel.ParagraphFormat.FirstLineIndent = 0
    $start = $sel.Range.Start
    $sel.TypeText($Text)
    $headingRange = $doc.Range($start, $sel.Range.End)
    try { $headingRange.ListFormat.RemoveNumbers() | Out-Null } catch {}
    $sel.TypeParagraph()
  }

  function Add-TitleNoToc {
    param([string]$Text)
    $sel.Style = $doc.Styles.Item($wdStyleNormal)
    $sel.Font.Bold = $true
    $sel.Font.Size = 14
    $sel.ParagraphFormat.Alignment = $wdAlignParagraphCenter
    $sel.ParagraphFormat.FirstLineIndent = 0
    $sel.TypeText($Text)
    $sel.TypeParagraph()
    $sel.Font.Bold = $false
    $sel.Font.Size = 14
    Set-NormalFormat
  }

  function Add-Page {
    $sel.InsertBreak($wdPageBreak)
  }

  function Add-TableBlock {
    param(
      [string]$Caption,
      [string[]]$Headers,
      [array]$Rows
    )
    Set-NormalFormat
    $sel.ParagraphFormat.FirstLineIndent = 0
    $sel.TypeText($Caption)
    $sel.TypeParagraph()
    $rowCount = $Rows.Count + 1
    $colCount = $Headers.Count
    $table = $doc.Tables.Add($sel.Range, $rowCount, $colCount)
    $table.Borders.Enable = $true
    $table.Rows.Item(1).Range.Bold = $true
    for ($c = 1; $c -le $colCount; $c++) {
      $table.Cell(1, $c).Range.Text = $Headers[$c - 1]
    }
    for ($r = 0; $r -lt $Rows.Count; $r++) {
      for ($c = 0; $c -lt $colCount; $c++) {
        $table.Cell($r + 2, $c + 1).Range.Text = [string]$Rows[$r][$c]
      }
    }
    $table.AutoFitBehavior(1)
    $after = $doc.Range($table.Range.End, $table.Range.End)
    $after.Select()
    $sel.TypeParagraph()
  }

  function Add-CodeBlock {
    param(
      [string]$Caption,
      [string]$Code
    )
    $sel.Style = $doc.Styles.Item($wdStyleNormal)
    $sel.Font.Bold = $false
    $sel.Font.Name = "Times New Roman"
    $sel.Font.Size = 14
    $sel.ParagraphFormat.Alignment = $wdAlignParagraphJustify
    $sel.ParagraphFormat.FirstLineIndent = 0
    $sel.TypeText($Caption)
    $sel.TypeParagraph()
    $sel.Font.Name = "Courier New"
    $sel.Font.Size = 9
    $sel.ParagraphFormat.LeftIndent = $word.CentimetersToPoints(0.5)
    $sel.ParagraphFormat.RightIndent = $word.CentimetersToPoints(0.3)
    foreach ($line in ($Code -split "`n")) {
      $sel.TypeText($line.TrimEnd())
      $sel.TypeParagraph()
    }
    $sel.Font.Name = "Times New Roman"
    $sel.Font.Size = 14
    $sel.ParagraphFormat.LeftIndent = 0
    $sel.ParagraphFormat.RightIndent = 0
    Set-NormalFormat
  }

  function Add-Figure {
    param(
      [string]$ImagePath,
      [string]$Caption
    )
    if (!(Test-Path -LiteralPath $ImagePath)) { return }
    $sel.ParagraphFormat.Alignment = $wdAlignParagraphCenter
    $sel.ParagraphFormat.FirstLineIndent = 0
    $shape = $sel.InlineShapes.AddPicture($ImagePath, $false, $true)
    if ($shape.Width -gt 450) {
      $shape.LockAspectRatio = $true
      $shape.Width = 450
    }
    $sel.TypeParagraph()
    $sel.Style = $doc.Styles.Item($wdStyleNormal)
    $sel.ParagraphFormat.Alignment = $wdAlignParagraphCenter
    $sel.TypeText($Caption)
    $sel.TypeParagraph()
    Set-NormalFormat
  }

