        "Необходимо разработать обучающий видеофрагмент трехмерной визуализации по теме принципа работы электронных схем, реализующих простейшие логические функции. Материал должен быть пригоден для демонстрации в колледже.",
        "В проекте должны быть реализованы функции NOT, AND и OR. Для каждой функции необходимо показать входные значения, правило вычисления, таблицу истинности и состояние выхода Y.",
        "Трехмерная сцена должна содержать условную электронную плату, проводники, переключатели, логический блок и выходной индикатор. Активные состояния должны отличаться цветом, свечением или движением сигнала.",
        "Приложение должно иметь автоматический режим мини-видео. Сценарий должен последовательно показывать ключевые состояния функций и давать возможность записать экран как готовый обучающий фрагмент.",
        "Дополнительно должен быть предусмотрен интерактивный режим. Пользователь должен иметь возможность изменять входы, выбирать функцию и сразу видеть пересчитанный результат.",
        "Проект должен запускаться локально в браузере, не использовать базу данных и иметь понятную структуру исходных файлов. Перед сдачей необходимо проверить сборку и соответствие таблицам истинности."
      )
    }

    if ($topicParagraphs.ContainsKey($Topic)) {
      $paragraphs = @($topicParagraphs[$Topic])
    } else {
      $paragraphs = @(
        "$Context Рассматриваемый вопрос связан с основной темой дипломного проекта и раскрывает один из аспектов разработки обучающей трехмерной визуализации.",
        "При описании темы «$Topic» важно учитывать учебную цель: пользователь должен понимать связь между входными сигналами, правилом функции и выходом Y.",
        "Практическое значение данного раздела состоит в том, что он уточняет требования к приложению и связывает техническую реализацию с методикой объяснения цифровой логики."
      )
    }
    $limit = [Math]::Min($Count, $paragraphs.Count)
    for ($i = 0; $i -lt $limit; $i++) {
      Add-Para $paragraphs[$i]
    }
    return

    $analysisExtras = @(
