  Add-Para "Таблица 14 является основой вычислительной логики проекта. При изменении входов приложение не использует заранее отрисованную картинку, а пересобирает состояние сцены в соответствии с правилом выбранной функции."
  Add-CodeBlock "Листинг 1 - Фрагмент описания логических функций" @'
type GateKind = "NOT" | "AND" | "OR";

const gates = {
  NOT: { inputs: ["A"], evaluate: (a) => Number(!a) },
  AND: { inputs: ["A", "B"], evaluate: (a, b = 0) => Number(Boolean(a && b)) },
  OR: { inputs: ["A", "B"], evaluate: (a, b = 0) => Number(Boolean(a || b)) },
};
'@
  Add-Para "В листинге 1 показан принцип хранения логики функций. Для каждой функции задается набор входов и правило вычисления выхода Y. Такой фрагмент подтверждает, что результат не вводится вручную, а рассчитывается по выбранной операции."
  Add-CodeBlock "Листинг 2 - Фрагмент обновления состояния сцены" @'
function buildStateContent(state: GateState) {
  currentInputs = normalizeInputs(state.kind, state.inputs);
  if (state.kind === "NOT") buildNot(currentInputs[0]);
  if (state.kind === "AND") buildAnd(currentInputs[0], currentInputs[1] ?? 0);
  if (state.kind === "OR") buildOr(currentInputs[0], currentInputs[1] ?? 0);

  renderTruthTable(state.kind, currentInputs);
  outputBadge.textContent = `Y = ${currentOutput}`;
  outputBadge.classList.toggle("is-on", Boolean(currentOutput));
}
'@
  Add-Para "Листинг 2 показывает связь между выбранной функцией, входными значениями, трехмерной сценой, таблицей истинности и индикатором Y. При смене состояния вызывается соответствующая сборка схемы, после чего обновляется интерфейс."
  Add-TableBlock "Таблица 15 - Алгоритм обновления состояния визуализации" @("Шаг", "Действие", "Результат") @(
